// In generate.ts transform callback — already handled generically:
if (schemaObject.format === 'date-time') {
  const allowString =
    (metadata.schema && 'in' in metadata.schema && metadata.schema.in === 'query') ||
    metadata.path?.includes('/parameters/query')
  return allowString
    ? factory.createUnionTypeNode([DATE, NULL, STRING])
    : DATE
}

// widgets.ts
import type { Client } from 'openapi-fetch'
import type { RequestOptions } from './common.js'
import type { WidgetCreate, operations, paths } from './schemas.js'
import { transformResponse } from './utils.js'

export class Widgets {
  constructor(private client: Client<paths, `${string}/${string}`>) {}

  public async create(widget: WidgetCreate, options?: RequestOptions) {
    const resp = await this.client.POST('/api/v1/widgets', { body: widget, ...options })
    return transformResponse(resp)
  }
}
